// Initialize persistent energy counters in context if not exist
let energy1 = context.get('energy1') || 1000.0;
let energy2 = context.get('energy2') || 2500.0;

// Simulate power variations (kW)
const power1 = parseFloat((10 + Math.random() * 5).toFixed(2));
const power2 = parseFloat((30 + Math.random() * 15).toFixed(2));

// Increment energy (kWh) = power * 10 seconds / 3600
energy1 += (power1 * 10) / 3600;
energy2 += (power2 * 10) / 3600;

// Save back to context
context.set('energy1', energy1);
context.set('energy2', energy2);

const msg1 = {
    topic: "factory/line_a/machine_001/energy",
    payload: {
        machine_id: "machine_001",
        location: "line_a",
        timestamp: Date.now(),
        power_kw: power1,
        energy_kwh: parseFloat(energy1.toFixed(3)),
        voltage_v: parseFloat((220 + (Math.random() - 0.5) * 4).toFixed(1)),
        current_a: parseFloat((power1 * 1000 / 220 / 0.95).toFixed(2)),
        power_factor: parseFloat((0.92 + Math.random() * 0.06).toFixed(2))
    }
};

const msg2 = {
    topic: "factory/line_a/machine_002/energy",
    payload: {
        machine_id: "machine_002",
        location: "line_a",
        timestamp: Date.now(),
        power_kw: power2,
        energy_kwh: parseFloat(energy2.toFixed(3)),
        voltage_v: parseFloat((220 + (Math.random() - 0.5) * 4).toFixed(1)),
        current_a: parseFloat((power2 * 1000 / 220 / 0.95).toFixed(2)),
        power_factor: parseFloat((0.91 + Math.random() * 0.07).toFixed(2))
    }
};

return [[msg1, msg2]];
